CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`billing`.`billing_frequency` (
    `billing_frequency_id` BIGINT COMMENT 'Primary key for billing_frequency',
    `parent_billing_frequency_id` BIGINT COMMENT 'Self-referencing FK on billing_frequency (parent_billing_frequency_id)',
    `anniversary_billing_flag` BOOLEAN COMMENT 'Indicates whether billing is triggered on the subscribers or contracts anniversary date rather than a fixed calendar date. True = anniversary-based; False = fixed calendar date. Common for subscriber and syndication license billing.',
    `applicable_billing_category` STRING COMMENT 'The primary billing category for which this frequency is used: subscriber (consumer subscription invoices), advertising (ad billing via Wide Orbit), carriage_fee (MVPD/cable operator carriage), syndication (content syndication license fees), or license (general licensing). Supports domain-specific billing workflows.',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether subscriptions or contracts using this billing frequency automatically renew at the end of each billing period without requiring explicit customer action. True = auto-renews; False = requires manual renewal.',
    `billing_day_of_month` STRING COMMENT 'The day of the month on which invoices are generated for this billing frequency (1–28 to avoid month-end ambiguity, or 31 to indicate end-of-month). Null for non-monthly frequencies or anniversary-date billing.',
    `billing_day_of_week` STRING COMMENT 'For weekly or bi-weekly billing frequencies, the day of the week on which invoices are generated. Null for non-weekly frequencies.',
    `billing_system_code` STRING COMMENT 'The corresponding frequency code or identifier in the source billing system (Zuora, Wide Orbit, or SAP S/4HANA) to enable cross-system reconciliation and integration mapping.',
    `billing_frequency_code` STRING COMMENT 'Short, machine-readable code uniquely identifying the billing frequency (e.g., MONTHLY, QUARTERLY, ANNUAL, WEEKLY, BIWEEKLY, SEMI_ANNUAL). Used as a stable external reference key in integrations with Zuora, Wide Orbit, and SAP S/4HANA.',
    `consolidation_flag` BOOLEAN COMMENT 'Indicates whether multiple charges within the same billing period should be consolidated into a single invoice for this frequency. True = consolidate; False = generate separate invoices per charge. Reduces invoice volume for high-frequency ad billing.',
    `created_at` TIMESTAMP COMMENT 'The UTC timestamp when this billing frequency record was first created in the system. Supports medallion bronze-to-silver lineage tracing per VREQ-035 cross-domain timestamp standard.',
    `currency_code` STRING COMMENT 'The default ISO 4217 three-letter currency code associated with this billing frequency (e.g., USD, EUR, GBP). Used when no currency is explicitly specified on the billing account or contract.',
    `billing_frequency_description` STRING COMMENT 'Detailed narrative description of the billing frequency, including business rules, applicable product lines, and any special conditions (e.g., Billed once per calendar month on the subscriber anniversary date).',
    `dunning_profile_code` STRING COMMENT 'Reference code identifying the dunning (collections escalation) profile applied to overdue invoices under this billing frequency. Maps to the dunning configuration in SAP S/4HANA or Zuora (e.g., STANDARD_DUNNING, CARRIAGE_DUNNING).',
    `effective_end_date` DATE COMMENT 'The calendar date after which this billing frequency definition is no longer valid. Null indicates an open-ended (indefinitely active) frequency. Used for temporal versioning and sunset planning.',
    `effective_start_date` DATE COMMENT 'The calendar date from which this billing frequency definition is valid and available for use. Supports temporal versioning of billing configurations.',
    `electronic_delivery_flag` BOOLEAN COMMENT 'Indicates whether invoices for this billing frequency are delivered electronically (e-invoice / EDI) by default. True = electronic delivery; False = paper or manual delivery. Supports PCI DSS and paperless billing compliance.',
    `frequency_type` STRING COMMENT 'Broad classification of the billing cadence pattern: recurring (regular periodic billing), one_time (single charge), usage_based (metered/consumption billing), or milestone (event-triggered billing). Drives revenue recognition treatment under ASC 606.',
    `grace_period_days` STRING COMMENT 'Number of additional days beyond the payment due date before a late payment penalty or service suspension is triggered. Supports subscriber retention and dispute resolution workflows.',
    `invoice_advance_days` STRING COMMENT 'Number of days before the billing period start date that the invoice is generated and dispatched to the customer. Supports cash flow planning and accounts receivable lead time management.',
    `late_fee_applicable_flag` BOOLEAN COMMENT 'Indicates whether a late payment fee is assessed when payment is not received within the grace period. True = late fee applies; False = no late fee for this frequency.',
    `late_fee_rate` DECIMAL(18,2) COMMENT 'The percentage rate applied to the overdue invoice balance to calculate the late payment fee (e.g., 0.0150 = 1.5% per month). Null when late_fee_applicable_flag is False.',
    `minimum_billing_amount` DECIMAL(18,2) COMMENT 'The minimum invoice amount that must be generated for this billing frequency. Invoices below this threshold may be held, combined, or waived per business rules. Expressed in the default currency.',
    `billing_frequency_name` STRING COMMENT 'Human-readable display name for the billing frequency (e.g., Monthly, Quarterly, Annual, Weekly). Displayed in subscriber portals, invoices, and sales proposals.',
    `payment_due_days` STRING COMMENT 'Number of days from invoice date by which payment is due (e.g., Net 30 = 30). Defines the standard payment terms associated with this billing frequency. Used in accounts receivable aging and dispute management.',
    `period_count` STRING COMMENT 'The number of period_unit intervals that constitute one complete billing cycle (e.g., 1 for monthly, 3 for quarterly, 12 for annual). Must be a positive integer.',
    `period_unit` STRING COMMENT 'The unit of time that defines one billing period (e.g., day, week, month, quarter, year). Combined with period_count to derive the full billing interval (e.g., period_count=3, period_unit=month = quarterly billing).',
    `proration_method` STRING COMMENT 'Defines how partial-period charges are calculated when a subscription starts or ends mid-cycle: daily (charge proportional to days used), full_period (charge full period regardless), or none (no proration applied). Impacts revenue recognition under ASC 606.',
    `revenue_recognition_method` STRING COMMENT 'The ASC 606 / IFRS 15 revenue recognition method associated with this billing frequency: straight_line (ratably over the period), event_based (at point of delivery), usage_based (as consumed), or milestone_based (upon milestone completion). Drives financial posting in SAP S/4HANA.',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of billing frequency options in subscriber portals, sales proposal tools, and billing configuration UIs. Lower values appear first.',
    `source_code` STRING COMMENT 'The native primary key or unique identifier of this billing frequency record in the originating source system (Zuora, Wide Orbit, or SAP S/4HANA). Enables cross-system reconciliation and lineage tracing per VREQ-035.',
    `source_system` STRING COMMENT 'The operational system of record from which this billing frequency definition originates: zuora (subscription billing), wide_orbit (advertising billing), sap_s4hana (financial/carriage billing), or internal (manually defined). Supports medallion lineage tracing per VREQ-035.',
    `billing_frequency_status` STRING COMMENT 'Lifecycle status of the billing frequency record: active (available for assignment to new accounts/contracts), inactive (temporarily disabled), or deprecated (no longer available for new assignments but retained for historical records).',
    `tax_inclusive_flag` BOOLEAN COMMENT 'Indicates whether the billed amount for this frequency includes applicable taxes (tax-inclusive pricing) or whether taxes are added on top of the base amount (tax-exclusive). Impacts invoice presentation and revenue recognition.',
    `updated_at` TIMESTAMP COMMENT 'The UTC timestamp when this billing frequency record was last modified. Supports change data capture (CDC) and medallion silver-layer incremental processing per VREQ-035.',
    CONSTRAINT pk_billing_frequency PRIMARY KEY(`billing_frequency_id`)
) COMMENT 'Master reference table for billing_frequency. Referenced by billing_frequency_ref_id.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`billing`.`revenue_recognition_rule` (
    `revenue_recognition_rule_id` BIGINT COMMENT 'Primary key for revenue_recognition_rule',
    `superseded_revenue_recognition_rule_id` BIGINT COMMENT 'Self-referencing FK on revenue_recognition_rule (superseded_revenue_recognition_rule_id)',
    `accounting_standard` STRING COMMENT 'The revenue accounting standard under which this rule is defined: ASC_606 (US GAAP), IFRS_15 (international), ASC_605 (legacy pre-606 standard, for historical rules), both (dual-reporting entities). Determines which financial reporting framework governs recognition timing and disclosure.',
    `allocation_method` STRING COMMENT 'Method used to allocate transaction price to performance obligations when a contract contains multiple obligations: standalone_selling_price (SSP-based), residual (residual approach), adjusted_market (adjusted market assessment), expected_cost_plus (expected cost plus margin), equal_allocation (equal split). Required for multi-element arrangements common in bundled subscription+advertising deals.',
    `applicable_product_type` STRING COMMENT 'Specifies the billing product type(s) to which this rule applies (e.g., linear_spot_ad, digital_preroll, mvpd_subscription, carriage_fee, syndication_license). Used by Zuora and Wide Orbit to auto-assign recognition rules to new contracts. [ENUM-REF-CANDIDATE: linear_spot_ad|digital_preroll|mvpd_subscription|carriage_fee|syndication_license|vod_subscription|avod_impression|makegood — promote to reference product]',
    `applicable_revenue_stream` STRING COMMENT 'The specific revenue stream or business unit this rule governs (e.g., Network TV Advertising, Cable Affiliate Fees, Streaming SVOD, Streaming AVOD/FAST, Content Syndication). Supports segment-level revenue reporting required under ASC 280 and IFRS 8. [ENUM-REF-CANDIDATE: network_tv_advertising|cable_affiliate_fees|streaming_svod|streaming_avod_fast|content_syndication|digital_advertising|international_licensing — promote to reference product]',
    `approval_required_flag` BOOLEAN COMMENT 'Indicates whether application of this rule to a new contract requires explicit finance/accounting approval (True) before revenue can be recognized, or whether it can be auto-applied by the billing system (False). High-value or complex arrangements typically require approval.',
    `approval_threshold_amount` DECIMAL(18,2) COMMENT 'The contract value threshold (in currency_code) above which explicit finance approval is required before this rule is applied. Contracts at or below this amount may be auto-approved. NULL if approval_required_flag is False.',
    `audience_guarantee_flag` BOOLEAN COMMENT 'Indicates whether contracts governed by this rule include audience delivery guarantees (True) — common in upfront and scatter advertising deals — or not (False). When True, variable consideration constraints and makegood provisions must be applied to the recognized revenue amount.',
    `constraint_threshold_pct` DECIMAL(18,2) COMMENT 'The percentage of estimated variable consideration that may be recognized without a significant revenue reversal risk, expressed as a percentage (0.00–100.00). Used when variable_consideration_method is constrained. For example, 80.00 means only 80% of estimated bonus revenue is recognized until the constraint is lifted.',
    `contract_modification_treatment` STRING COMMENT 'Defines how contract modifications (e.g., upfront deal amendments, carriage fee renegotiations) are accounted for: prospective (treat as new contract going forward), cumulative_catch_up (adjust cumulative revenue recognized), separate_contract (treat modification as a separate contract). Aligns with ASC 606-10-25-12.',
    `created_at` TIMESTAMP COMMENT 'The timestamp when this revenue recognition rule record was first created in the enterprise data model. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports medallion-layer lineage tracing per VREQ-035.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to this rule (e.g., USD, GBP, EUR). Rules may be currency-specific for international carriage fee and syndication licensing arrangements. Defaults to USD for domestic US broadcasting operations.',
    `deferral_method` STRING COMMENT 'Specifies how deferred revenue is released to earned revenue over time: straight_line (equal amounts per period), units_of_delivery (proportional to units delivered, e.g., episodes aired), proportional_performance (based on effort/cost incurred), none (no deferral — immediate recognition). Drives deferred revenue balance calculations in SAP S/4HANA.',
    `effective_end_date` DATE COMMENT 'The date after which this rule is no longer applicable to new contracts. NULL for open-ended rules. When populated, the rule is superseded by a replacement rule on this date. Existing contracts continue to use the rule until their term ends.',
    `effective_start_date` DATE COMMENT 'The date from which this revenue recognition rule is effective and may be applied to new contracts. Rules are date-effective to support accounting standard transitions (e.g., ASC 605 to ASC 606 transition date of 2018-01-01 for calendar-year public companies).',
    `external_audit_reference` STRING COMMENT 'Reference number or memo identifier from the external auditors workpapers or technical accounting memo that supports the accounting treatment defined by this rule. Provides linkage between the data model and audit documentation for SEC reporting and Big 4 audit support.',
    `gl_contract_asset_account_code` STRING COMMENT 'The SAP S/4HANA GL account code for contract assets (unbilled receivables) where revenue has been recognized but not yet invoiced. Applicable for milestone-based content delivery deals where recognition precedes billing.',
    `gl_deferred_revenue_account_code` STRING COMMENT 'The SAP S/4HANA General Ledger account code for the deferred (unearned) revenue liability balance associated with this rule (e.g., 2300000). Used to track contract liabilities on the balance sheet until performance obligations are satisfied.',
    `gl_revenue_account_code` STRING COMMENT 'The SAP S/4HANA General Ledger account code to which recognized revenue is posted under this rule (e.g., 4100000 for subscription revenue, 4200000 for advertising revenue). Ensures correct financial statement classification and segment reporting.',
    `last_reviewed_date` DATE COMMENT 'The date on which this revenue recognition rule was last reviewed by the accounting policy team for continued appropriateness and compliance with current accounting standards. Supports SOX control evidence and audit trail requirements.',
    `license_type` STRING COMMENT 'For IP licensing revenue (content, format, music sync): right_to_use (point-in-time recognition — licensee has right to use IP as it exists at grant date), right_to_access (over-time recognition — licensee has right to access IP throughout license period), none (not an IP license arrangement). Directly determines recognition timing per ASC 606-10-55-58.',
    `makegood_eligible_flag` BOOLEAN COMMENT 'Indicates whether revenue recognized under this rule is subject to makegood obligations (True) or not (False). Makegoods are compensatory ad units issued when audience delivery guarantees are not met. When True, recognized revenue may be subject to reversal or offset upon makegood issuance.',
    `maximum_contract_term_days` STRING COMMENT 'The maximum contract duration in days for which this rule is applicable. NULL indicates no upper bound. Used to scope rules to short-term spot advertising (e.g., ≤1 day) vs. long-term carriage fee agreements (e.g., up to 1825 days / 5 years).',
    `maximum_contract_value` DECIMAL(18,2) COMMENT 'The maximum contract or transaction value (in the rules currency) for which this recognition rule is applicable. Contracts above this threshold may require escalated review or a different rule. NULL indicates no upper bound.',
    `minimum_contract_term_days` STRING COMMENT 'The minimum contract duration in days for which this rule is applicable. For example, a ratable subscription rule may require a minimum 30-day term. Contracts shorter than this threshold may use a different recognition approach.',
    `minimum_contract_value` DECIMAL(18,2) COMMENT 'The minimum contract or transaction value (in the rules currency) for which this recognition rule is applicable. Contracts below this threshold may be subject to a simplified recognition approach or a different rule. Expressed in the currency defined by currency_code.',
    `multi_element_arrangement_flag` BOOLEAN COMMENT 'Indicates whether this rule applies to contracts with multiple performance obligations (True) — such as bundled subscription + premium content + advertising packages — requiring transaction price allocation, or single-element contracts (False).',
    `next_review_date` DATE COMMENT 'The date by which this rule must next be reviewed by the accounting policy team. Typically set annually or upon material changes to the underlying business arrangement or accounting standards.',
    `performance_obligation_type` STRING COMMENT 'Identifies the ASC 606 / IFRS 15 performance obligation structure: single (one distinct obligation), series (series of distinct goods/services), bundle (combined obligations), license (IP license), service (ongoing service). Determines how transaction price is allocated and when revenue is recognized.',
    `policy_owner` STRING COMMENT 'The name or identifier of the finance/accounting team or individual responsible for maintaining this rule (e.g., VP Revenue Accounting, Corporate Controller). Used for governance and SOX control ownership documentation.',
    `practical_expedient_applied` STRING COMMENT 'Identifies any ASC 606 / IFRS 15 practical expedient elected for this rule: right_to_invoice (recognize revenue equal to amount invoiced when right to invoice corresponds to performance), portfolio (apply to portfolio of contracts with similar characteristics), financing_component (ignore financing component when contract term ≤ 12 months), none. Reduces complexity for high-volume advertising billing.',
    `principal_agent_indicator` STRING COMMENT 'Indicates whether the entity acts as principal (recognizes gross revenue) or agent (recognizes net revenue/commission) for transactions governed by this rule. Critical for advertising representation arrangements, content distribution deals, and affiliate fee pass-through scenarios.',
    `recognition_period_unit` STRING COMMENT 'The unit of time or delivery over which revenue is spread when using ratable or units-of-delivery deferral: day, week, month, quarter, year, episode (for content licensing), impression (for digital/AVOD advertising). Determines the granularity of revenue schedule entries.',
    `recognition_trigger` STRING COMMENT 'The specific business event that triggers revenue recognition under this rule: broadcast_date (ad spot airs), invoice_date (billing cycle close), contract_start (subscription activation), delivery_confirmation (content asset delivered), milestone_completion (production milestone met), period_end (calendar/fiscal period close). Mapped to Wide Orbit and Zuora event hooks.',
    `requires_ssp_documentation_flag` BOOLEAN COMMENT 'Indicates whether this rule requires documented standalone selling price (SSP) analysis for transaction price allocation (True) or not (False). Required for bundled deals where observable SSP is not directly available and must be estimated.',
    `retroactive_adjustment_allowed_flag` BOOLEAN COMMENT 'Indicates whether retroactive revenue adjustments (catch-up entries) are permitted under this rule (True) — applicable for cumulative catch-up contract modifications and variable consideration true-ups — or whether only prospective adjustments are allowed (False).',
    `revenue_category` STRING COMMENT 'Broad revenue stream category to which this rule applies: subscription (MVPD/OTT subscriber fees), advertising (spot, scatter, upfront), carriage_fee (affiliate/retransmission consent fees), syndication (content licensing to third parties), licensing (music sync, format rights), makegood (compensatory ad units), other. Drives revenue line reporting in SAP S/4HANA.',
    `revenue_schedule_frequency` STRING COMMENT 'The frequency at which revenue schedule entries are generated for contracts governed by this rule: daily (AVOD impression-level), weekly, monthly (standard subscription), quarterly (carriage fee), annually (annual license), per_episode (content syndication), per_impression (programmatic digital), one_time (spot ad). Drives the revenue waterfall schedule in SAP S/4HANA RAR.',
    `rule_code` STRING COMMENT 'Short, externally-known alphanumeric code uniquely identifying this rule (e.g., RR-SUB-001, RR-ADV-SPOT). Used as a stable business key referenced by billing systems such as Zuora and SAP S/4HANA revenue accounting modules.',
    `rule_description` STRING COMMENT 'Detailed narrative describing the business logic, conditions, and accounting treatment applied by this rule. Supports auditor review and finance team documentation requirements.',
    `rule_name` STRING COMMENT 'Human-readable name of the revenue recognition rule (e.g., Subscription Straight-Line Monthly, Spot Ad Broadcast Date Recognition). Displayed in SAP S/4HANA revenue accounting and Zuora billing dashboards.',
    `rule_status` STRING COMMENT 'Current lifecycle status of the rule: active (in use for new contracts), inactive (suspended, not applied to new contracts), draft (under development, not yet approved), deprecated (replaced by a newer rule, retained for historical contracts), under_review (pending accounting policy review). Controls whether the rule is available for assignment in Zuora and Wide Orbit.',
    `rule_type` STRING COMMENT 'Classifies the recognition pattern: point_in_time (e.g., one-time ad spot airing), over_time (e.g., subscription ratable), milestone (e.g., content delivery milestone), usage_based (e.g., AVOD/FAST impressions), ratable (straight-line over contract term), event_driven (e.g., license window open). Aligns with ASC 606 performance obligation satisfaction criteria.',
    `significant_financing_flag` BOOLEAN COMMENT 'Indicates whether the contract contains a significant financing component that requires adjustment of the transaction price for the time value of money (True) or not (False). Relevant for multi-year carriage fee agreements or long-term syndication deals with extended payment terms.',
    `source_system` STRING COMMENT 'The originating system where this rule was defined or is primarily maintained: zuora (subscription billing), wide_orbit (advertising billing), sap_s4hana (financial/revenue accounting), manual (finance team-defined rule not in a billing system), other. Supports medallion-layer lineage tracing per VREQ-035.',
    `source_system_rule_code` STRING COMMENT 'The native identifier of this rule in the originating source system (e.g., Zuora Revenue Rule ID, SAP RAR Condition Type). Enables reconciliation between the enterprise data model and operational billing/accounting systems. Supports bronze-to-silver lineage tracing.',
    `superseded_by_rule_code` STRING COMMENT 'The rule_code of the replacement rule that supersedes this rule when it is deprecated or expires. Provides a forward-reference chain for auditors tracing the evolution of accounting policies. NULL if this rule has not been superseded.',
    `tax_treatment` STRING COMMENT 'Specifies the tax treatment associated with revenue recognized under this rule: taxable (subject to applicable sales/use/VAT tax), exempt (tax-exempt revenue stream), deferred_tax (timing difference creates deferred tax asset/liability), not_applicable (no tax implications). Integrates with SAP S/4HANA tax determination.',
    `updated_at` TIMESTAMP COMMENT 'The timestamp when this revenue recognition rule record was last modified. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC) in the Databricks Silver layer and audit trail maintenance per VREQ-035.',
    `variable_consideration_method` STRING COMMENT 'Method for estimating variable consideration (e.g., ratings-based bonuses, audience guarantee makegoods, volume rebates): expected_value (probability-weighted), most_likely_amount (single most likely outcome), constrained (limited to amount unlikely to reverse), none (no variable consideration). Required for upfront and scatter advertising deals with audience guarantees.',
    CONSTRAINT pk_revenue_recognition_rule PRIMARY KEY(`revenue_recognition_rule_id`)
) COMMENT 'Master reference table for revenue_recognition_rule. Referenced by revenue_recognition_rule_ref_id.';

